**Models**

```python
# models.py
import Flask
from flask_sqlalchemy import SQLAlchemy
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(64), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)
    role = db.Column(db.String(64), nullable=False)  # patient or provider

class Provider(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(64), nullable=False)
    specialty = db.Column(db.String(64), nullable=False)
    availability = db.Column(db.String(64), nullable=False)

class Appointment(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    provider_id = db.Column(db.Integer, db.ForeignKey('provider.id'), nullable=False)
    date = db.Column(db.Date, nullable=False)
    time = db.Column(db.Time, nullable=False)
```

**Routes**

```python
# routes.py
from flask import Flask, render_template, redirect, url_for, flash
from flask_login import login_user, logout_user, current_user
from app.forms import RegistrationForm, LoginForm, SearchForm, BookAppointmentForm
from app.models import User, Provider, Appointment

app = Flask(__name__)

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/register', methods=['GET', 'POST'])
def register():
    form = RegistrationForm()
    if form.validate_on_submit():
        user = User(username=form.username.data, password=form.password.data, role=form.role.data)
        db.session.add(user)
        db.session.commit()
        return redirect(url_for('login'))
    return render_template('register.html', form=form)

@app.route('/login', methods=['GET', 'POST'])
def login():
    form = LoginForm()
    if form.validate_on_submit():
        user = User.query.filter_by(username=form.username.data).first()
        if user and user.password == form.password.data:
            login_user(user)
            return redirect(url_for('profile'))
    return render_template('login.html', form=form)

@app.route('/search', methods=['GET', 'POST'])
def search():
    form = SearchForm()
    if form.validate_on_submit():
        providers = Provider.query.filter_by(specialty=form.specialty.data).all()
        return render_template('search.html', providers=providers)
    return render_template('search.html', form=form)

@app.route('/book_appointment', methods=['GET', 'POST'])
def book_appointment():
    form = BookAppointmentForm()
    if form.validate_on_submit():
        appointment = Appointment(user_id=current_user.id, provider_id=form.provider_id.data, date=form.date.data, time=form.time.data)
        db.session.add(appointment)
        db.session.commit()
        return redirect(url_for('profile'))
    return render_template('book_appointment.html', form=form)

@app.route('/manage_appointment')
def manage_appointment():
    appointments = Appointment.query.filter_by(user_id=current_user.id).all()
    return render_template('manage_appointment.html', appointments=appointments)

@app.route('/cancel_appointment')
def cancel_appointment():
    appointment = Appointment.query.filter_by(id=form.appointment_id.data).first()
    if appointment:
        db.session.delete(appointment)
        db.session.commit()
    return redirect(url_for('manage_appointment'))

# Send reminders
import schedule
import time

def send_reminders():
    appointments = Appointment.query.filter_by(date=datetime.date.today() + datetime.timedelta(days=1)).all()
    for appointment in appointments:
        # Send reminder email or SMS
        pass

schedule.every().day.at("08:00").do(send_reminders)  # Send reminders at 8:00 AM every day
while True:
    schedule.run_pending()
    time.sleep(1)
